  })
}));

describe('sample router auth', () => {
  beforeEach(() => {
    mockRoutes.length = 0;
    jest.resetModules();
  });

  test('allows creator-capable roles to create and edit samples and boxes', () => {
    require('../../routes/sample.router');

    const createRoles = ['admin', 'production', 'sourcing_manager', 'vendor'];
    const routes = [
      ['post', '/boxes'],
      ['put', '/boxes/:id'],
      ['post', '/'],
      ['put', '/:id']
    ];

    for (const [method, path] of routes) {
